func (s *SSH) CopyFile(src, dst string) error {
	srcHash, err := hash.Sha256WithFile(src)
	if err != nil {
		return err
	}
	hashFile := "/tmp" + dst + ".sha256"
	buffer := new(bytes.Buffer)
	buffer.WriteString(fmt.Sprintf("%s %s", srcHash, dst))
	_ = s.WriteFile(buffer, hashFile)
	_, err = s.CombinedOutput(fmt.Sprintf("sha256sum --check --status %s", hashFile))
	if err == nil { // means dst exist and same as src
		logger.Log.Infof("skip copy `%s` because already existed", src)
		return nil
	}
	logger.Log.Infof("[%s] copy `%s` to %q", s.addr, src, dst)

	config := &ssh.ClientConfig{
		User:            s.User,
		Auth:            s.authMethods,
		HostKeyCallback: ssh.InsecureIgnoreHostKey(),
	}
	client, err := s.dialer.Dial("tcp", s.addr, config)
	if err != nil {
		err = wait.Poll(5*time.Second, time.Duration(s.Retry)*5*time.Second, func() (bool, error) {
			if client, err = s.dialer.Dial("tcp", s.addr, config); err != nil {
				return false, err
			}
			return true, nil
		})
	}
	if err != nil {
		return err
	}
	defer client.Close()

	sftpClient, err := sftp.NewClient(client)
	if err != nil {
		return err
	}
	defer sftpClient.Close()

	srcFile, err := os.Open(src)

	if err != nil {
		return fmt.Errorf("open file error:%s:%s", src, err)
	}
	defer srcFile.Close()

	_ = sftpClient.MkdirAll(path.Dir(dst))
	dstFile, err := sftpClient.Create(dst)
	if err != nil {
		return fmt.Errorf("create file error:%s:%s", dst, err)
	}
	defer dstFile.Close()

	_, err = dstFile.ReadFrom(srcFile)
	return err
}

func TcpPing(addr string, isTls bool) error {
	if isTls {
		conn, err := tls.DialWithDialer(&net.Dialer{Timeout: 5 * time.Second}, "tcp", addr, &tls.Config{InsecureSkipVerify: true})
		if err != nil {
			return errors.Wrap(err, fmt.Sprintf("tls tcp ping addr %s failed: %v", addr, err))
		}
		defer conn.Close()
	} else {
		conn, err := net.DialTimeout("tcp", addr, 5*time.Second)
		if err != nil {
			return errors.Wrap(err, fmt.Sprintf("tcp ping addr %s failed: %v", addr, err))
		}
		defer conn.Close()
	}
	return nil
}

func NewMinIoClient(vars map[string]interface{}) (*minIoClient, error) {
	var endpoint string
	var accessKeyID string
	var secretAccessKey string
	var ssl string
	if _, ok := vars["endpoint"]; ok {
		endpoint = vars["endpoint"].(string)
	} else {
		return nil, errors.New(ParamEmpty)
	}
	if _, ok := vars["accessKey"]; ok {
		accessKeyID = vars["accessKey"].(string)
	} else {
		return nil, errors.New(ParamEmpty)
	}
	if _, ok := vars["secretKey"]; ok {
		secretAccessKey = vars["secretKey"].(string)
	} else {
		return nil, errors.New(ParamEmpty)
	}

	if _, ok := vars["ssl"]; ok {
		ssl = vars["ssl"].(string)
	} else {
		return nil, errors.New(ParamEmpty)
	}
	secure := false
	tlsConfig := &tls.Config{}
	if ssl == "https" {
		secure = true
		tlsConfig.InsecureSkipVerify = true
	}
	var transport http.RoundTripper = &http.Transport{
		TLSClientConfig: tlsConfig,
	}
	client, err := minio.New(endpoint, &minio.Options{
		Creds:     credentials.NewStaticV4(accessKeyID, secretAccessKey, ""),
		Secure:    secure,
		Transport: transport,
	})
	if err != nil {
		return nil, err
	}
	return &minIoClient{
		client: client,
		Vars:   vars,
	}, nil
}

func GetStringKey(val string) string {
	sha := sha1.New()
	sha.Write([]byte(val))
	result := hex.EncodeToString(sha.Sum([]byte("")))
	reg := regexp.MustCompile(`[0-9]`)
	return reg.ReplaceAllString(result, "")
}

func (l *LdapClient) Connect() error {
	var err error
	if l.Config.TLS == "ENABLE" {
		l.Conn, err = ldap.DialTLS("tcp", fmt.Sprintf("%s:%s", l.Config.Endpoint, l.Config.Port), &tls.Config{
			InsecureSkipVerify: true,
		})
	} else {
		l.Conn, err = ldap.Dial("tcp", fmt.Sprintf("%s:%s", l.Config.Endpoint, l.Config.Port))
	}
	if err != nil {
		return err
	}
	err = l.Conn.Bind(l.Config.UserName, l.Config.Password)
	if err != nil {
		return err
	}
	return err
}

func CheckConn(username, password, endpoint string) error {
	url := fmt.Sprintf("%s/%s", endpoint, RepoUrl)
	request, err := http.NewRequest(http.MethodGet, url, nil)
	if err != nil {
		return err
	}
	if username != "" && password != "" {
		request.SetBasicAuth(username, password)
	} else {
		return errors.New("password is required")
	}

	client := &http.Client{
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
		},
		Timeout: 2 * time.Second,
	}
	resp, err := client.Do(request)
	if err != nil {
		return err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return errors.New(resp.Status)
	}

	return nil
}

func ChartmuseumProxy(ctx context.Context) {
	clusterName := ctx.Params().Get("cluster_name")
	proxyPath := ctx.Params().Get("p")
	if clusterName == "" {
		_, _ = ctx.JSON(http.StatusBadRequest)
		return
	}
	endpoint, err := clusterService.GetRouterEndpoint(clusterName)
	if err != nil {
		_, _ = ctx.JSON(http.StatusInternalServerError)
		return
	}
	u, err := url.Parse(fmt.Sprintf("http://%s", endpoint.Address))
	if err != nil {
		_, _ = ctx.JSON(http.StatusInternalServerError)
		return
	}
	proxy := httputil.NewSingleHostReverseProxy(u)
	proxy.Transport = &http.Transport{
		TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
	}
	req := ctx.Request()
	req.Host = fmt.Sprintf(constant.DefaultChartmuseumIngress)
	req.URL.Path = proxyPath
	proxy.ServeHTTP(ctx.ResponseWriter(), req)
}

